mapper.select:
SELECT FROM t_category WHERE deleted = 0 AND id IN
#{id}
ORDER BY id ASC FOR UPDATE

mapper.update:
UPDATE t_category
SET sort_order = #{sortOrder},
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
WHERE id = #{id}
  AND deleted = 0

mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM t_article
    WHERE category_id = #{categoryId}
      AND deleted = 0
)
